<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';
$portal=portalEstudianteCabecera('Mis capacitaciones','cursos','Pagos confirmados, asignación de clase y acceso académico.');$pdo=obtenerConexion();
$q=$pdo->prepare("SELECT a.id,a.codigo,a.nombre,a.descripcion,i.id inscripcion_id,i.estado,i.asignacion_limite_at,CONCAT_WS(' ',d.nombre,d.apellido) docente,s.codigo seccion,s.nombre seccion_nombre,s.horario,s.fecha_inicio,'inscripcion' origen FROM inscripciones_capacitacion i JOIN asignaturas a ON a.id=i.asignatura_id LEFT JOIN usuarios d ON d.id=i.docente_id LEFT JOIN capacitacion_secciones s ON s.id=i.seccion_id WHERE i.usuario_id=:u AND i.estado IN('pendiente_asignacion','inscrito','finalizado') UNION ALL SELECT a.id,a.codigo,a.nombre,a.descripcion,NULL,ed.estado,NULL,CONCAT_WS(' ',d.nombre,d.apellido),NULL,NULL,NULL,NULL,'heredado' FROM estudiantes_docentes ed JOIN asignaturas a ON a.id=ed.asignatura_id JOIN usuarios d ON d.id=ed.docente_id WHERE ed.estudiante_id=:u2 AND ed.estado='activo' AND NOT EXISTS(SELECT 1 FROM inscripciones_capacitacion i2 WHERE i2.usuario_id=ed.estudiante_id AND i2.asignatura_id=ed.asignatura_id) ORDER BY nombre");$q->execute(['u'=>$portal['perfil']['id'],'u2'=>$portal['perfil']['id']]);$cursos=$q->fetchAll();
?>
<div class="row g-4"><?php foreach($cursos as$c):?><div class="col-md-6"><article class="card h-100"><div class="card-body"><div class="d-flex justify-content-between"><span class="badge bg-primary"><?=atenea_e($c['codigo'])?></span><?php if($c['origen']==='heredado'):?><span class="badge bg-secondary">Registro heredado</span><?php endif;?></div><h2 class="h4 mt-3"><?=atenea_e($c['nombre'])?></h2><p class="text-muted"><?=atenea_e((string)$c['descripcion'])?></p><?php if($c['estado']==='pendiente_asignacion'):?><div class="alert alert-warning"><strong>Pago confirmado.</strong> Estamos buscando una sección con docente y cupo. Este proceso puede tardar un máximo de 3 días y no debes pagar nuevamente.<?php if($c['asignacion_limite_at']):?><small class="d-block mt-1">Plazo estimado: <?=date('d/m/Y H:i',strtotime($c['asignacion_limite_at']))?></small><?php endif;?></div><?php else:?><dl class="row small"><dt class="col-4">Sección</dt><dd class="col-8"><?=atenea_e($c['seccion_nombre']?:($c['seccion']?:'Por confirmar'))?></dd><dt class="col-4">Docente</dt><dd class="col-8"><?=atenea_e($c['docente']?:'Por confirmar')?></dd><dt class="col-4">Horario</dt><dd class="col-8"><?=atenea_e($c['horario']?:'Por confirmar')?></dd><dt class="col-4">Inicio</dt><dd class="col-8"><?=atenea_e($c['fecha_inicio']?date('d/m/Y',strtotime($c['fecha_inicio'])):'Por confirmar')?></dd></dl><?php if($c['origen']==='inscripcion'):?><a class="btn btn-primary" href="<?=atenea_url('src/estudiantes/curso.php?id='.(int)$c['id'])?>">Abrir curso</a> <a class="btn btn-outline-primary" href="<?=atenea_url('src/estudiantes/clase.php')?>">Ver mi clase</a><?php else:?><a class="btn btn-outline-primary" href="<?=atenea_url('src/comunicaciones/agenda.php?capacitacion='.(int)$c['id'])?>">Consultar acceso académico</a><?php endif;?><?php endif;?></div></article></div><?php endforeach;?><?php if(!$cursos):?><div class="col-12"><div class="card"><div class="aula-empty"><i class="bi bi-journal-bookmark"></i><h2 class="h4 mt-3">No hay capacitaciones asignadas</h2><p class="mb-0">Tu cuenta no tiene pagos académicos confirmados ni matrículas activas.</p></div></div></div><?php endif;?></div>
<?php portalEstudiantePie();
